public void testPropertyOptionFalseValue() throws Exception
{
    Options opts = new Options();
    opts.addOption("a", false, "option a");
    opts.addOption("b", false, "option b");

    String[] args = new String[] { };

    Properties properties = new Properties();
    properties.put("a", "false");
    properties.put("b", "no");

    CommandLine cmd = parse(parser, opts, args, properties);

    assertFalse(cmd.hasOption("a"));
    assertFalse(cmd.hasOption("b"));
}

public void testPropertyOptionWithArg() throws Exception
{
    Options opts = new Options();
    opts.addOption("f", true, "option f with arg");

    String[] args = new String[] { };

    Properties properties = new Properties();
    properties.put("f", "value1");

    CommandLine cmd = parse(parser, opts, args, properties);

    assertTrue(cmd.hasOption("f"));
    assertEquals("value1", cmd.getOptionValue("f"));
}

public void testThreeOptionsFromTwoGroups() throws Exception
{
    OptionGroup group3 = new OptionGroup();
    group3.addOption(new Option("p", null));
    group3.addOption(new Option("q", null));
    _options.addOptionGroup(group3);

    String[] args = new String[] { "-f" };

    Properties properties = new Properties();
    properties.put("p", "true");

    CommandLine cl = parser.parse(_options, args, properties);
    assertTrue(cl.hasOption("f"));
    assertTrue(cl.hasOption("p"));
    assertTrue(!cl.hasOption("q"));
}
